# Cibler l'ancien panel avec class="cpx-grid3"
pattern = r'<!-- PANEL CRYPTO -->\s*<div id="panel-crypto".*?(?=\n\s*<!-- TRACKING -->)'
match = re.search(pattern, html, re.DOTALL)
if match:
    html = html[:match.start()] + new_panel + '\n\n' + html[match.end():]
    print("OK - Panel crypto remplace (25 coins)")
else:
    # Essayer avec juste le div
    pattern2 = r'<div id="panel-crypto"[^>]*>.*?(?=\n\s*<!-- TRACKING -->)'
    match2 = re.search(pattern2, html, re.DOTALL)
    if match2:
        html = html[:match2.start()] + new_panel + '\n\n' + html[match2.end():]
        print("OK - Panel crypto remplace via pattern2 (25 coins)")
    else:
        print("ERREUR - Panel introuvable")
        # Debug: chercher où est panel-crypto
        idx = html.find('id="panel-crypto"')
        if idx >= 0:
            print(f"panel-crypto trouve a index {idx}")
            print("Contexte: " + html[idx:idx+200])

with open('zama.html', 'w', encoding='utf-8') as f:
    f.write(html)

print("Termine!")
